#include<bits/stdc++.h>
using namespace std;

map<string,bool> m;
int main(){
    int n,mm,ans=0;
    cin>>n>>mm;
    getchar();
    for(int i=1;i<=n;i++){
        string a;
        getline(cin,a);
        if (a[a.size()-1]!=(char)13) a=a+char(13);
        m[a]=1;
    }
    for(int i=1;i<=mm;i++){
        string x;
        getline(cin,x);
        if (x[x.size()-1]!=(char)13) x=x+char(13);
        if(m[x]) ans++;
    }
    cout<<ans;
    return 0;
}
